diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index c1ce364eb179..9532469a7b43 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1872,6 +1872,55 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     return replaceInstUsesWith(I, Builder.CreateZExtOrTrunc(Ret, I.getType()));
   }

+
+  // Fold ceiling division idiom:
+  // (x >> k) + ((x & (2^k-1)) != 0) --> (x + (2^k-1)) >> k
+  // This is equivalent to: ceil(x / 2^k) = (x + (2^k - 1)) >> k
+  // Only apply when we can prove x + (2^k - 1) won't overflow.
+  // Fold ceiling division idiom:
+  // (x >> k) + ((x & (2^k-1)) != 0) --> (x + (2^k-1)) >> k
+  // This is equivalent to: ceil(x / 2^k) = (x + (2^k - 1)) >> k
+  // Only apply when we can prove x + (2^k - 1) won't overflow.
+  Value *LshrVal;
+  const APInt *ShiftAmt;
+  const APInt *Mask;
+  if ((match(LHS, m_OneUse(m_LShr(m_Value(LshrVal), m_APInt(ShiftAmt)))) &&
+       match(RHS, m_ZExt(m_SpecificICmp(CmpInst::ICMP_NE,
+                                 m_OneUse(m_And(m_Specific(LshrVal),
+                                                          m_APInt(Mask))),
+                                 m_ZeroInt())))) ||
+      (match(RHS, m_OneUse(m_LShr(m_Value(LshrVal), m_APInt(ShiftAmt)))) &&
+       match(LHS, m_ZExt(m_SpecificICmp(CmpInst::ICMP_NE,
+                                 m_OneUse(m_And(m_Specific(LshrVal),
+                                                          m_APInt(Mask))),
+                                 m_ZeroInt()))))) {
+    unsigned ShiftAmtVal = ShiftAmt->getLimitedValue();
+    if (ShiftAmtVal < BitWidth &&
+        *Mask == APInt::getLowBitsSet(BitWidth, ShiftAmtVal)) {
+      // Check if x + mask won't overflow using range analysis that includes
+      // range attributes.
+      ConstantRange LshrRange = computeConstantRangeIncludingKnownBits(
+          LshrVal, /*ForSigned=*/false, SQ.getWithInstruction(&I));
+      ConstantRange MaskRange(*Mask, *Mask + 1);
+      // Check for unsigned overflow
+      bool CanAddNUW = LshrRange.unsignedAddMayOverflow(MaskRange) ==
+                       ConstantRange::OverflowResult::NeverOverflows;
+      // Check for signed overflow if the add has NSW
+      bool CanAddNSW = false;
+      if (I.hasNoSignedWrap()) {
+        CanAddNSW = LshrRange.signedAddMayOverflow(MaskRange) ==
+                    ConstantRange::OverflowResult::NeverOverflows;
+      }
+      if (CanAddNUW || CanAddNSW) {
+        Value *Add = Builder.CreateAdd(LshrVal,
+                                       ConstantInt::get(Ty, *Mask), "",
+                                       CanAddNUW, CanAddNSW);
+        return BinaryOperator::CreateLShr(Add, ConstantInt::get(Ty, ShiftAmtVal));
+      }
+    }
+  }
+
+
   if (Instruction *Res = foldSquareSumInt(I))
     return Res;

